function Message({ sender, text }) {
    const isUser = sender === "user";

    return (
        <div
            style={{
                textAlign: isUser ? "right" : "left",
                margin: "10px 0",
            }}
        >
            <span
                style={{
                    display: "inline-block",
                    padding: "10px 14px",
                    borderRadius: "12px",
                    maxWidth: "70%",
                    background: isUser ? "#4f46e5" : "#e5e7eb",
                    color: isUser ? "white" : "black",
                }}
            >
                {text}
            </span>
        </div>
    );
}

export default Message;
